define(["core/ajax","core/notification"],function(Ajax,Notification){var getPaymentCode=function(component,paymentArea,itemId,description){var request={methodname:"paygw_webirr_get_code",args:{component:component,paymentarea:paymentArea,itemid:itemId,description:description}};return Ajax.call([request])[0]};var getPaymentStatus=function(paymentId){var request={methodname:"paygw_webirr_get_status",args:{paymentid:paymentId}};return Ajax.call([request])[0]};return{getPaymentCode:getPaymentCode,getPaymentStatus:getPaymentStatus}});
